import{_ as a,o as t,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"AI 绘画入门知识库","text":"从底模、Prompt、LoRA 到工作流","tagline":"面向零基础用户的公开版 AI 绘画概念指南","actions":[{"theme":"brand","text":"开始入门","link":"/guide/getting-started"},{"theme":"alt","text":"查看术语表","link":"/glossary"}]},"features":[{"title":"先理解概念","details":"用直观语言解释底模、VAE、文本编码器、采样器、LoRA、ControlNet 和工作流。"},{"title":"再选择工具","details":"区分 Web 平台、本地 WebUI、ComfyUI、模型网站和素材网站各自适合做什么。"},{"title":"最后形成流程","details":"从提示词、模型选择、参数调试到复用工作流，逐步建立稳定的出图方法。"}]},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":null}'),o={name:"index.md"};function r(s,e,n,d,c,h){return t(),i("div",null,[...e[0]||(e[0]=[l('<h2 id="这份知识库适合谁" tabindex="-1">这份知识库适合谁 <a class="header-anchor" href="#这份知识库适合谁" aria-label="Permalink to &quot;这份知识库适合谁&quot;">​</a></h2><p>这份文档面向刚接触 AI 绘画的人：你可能听过 Stable Diffusion、ComfyUI、LoRA、Pony、FLUX、Civitai，但还不清楚它们之间是什么关系。</p><p>知识库的目标不是堆下载链接，而是先把常见概念讲清楚。理解这些概念后，再去看教程、下载模型、搭工作流会省很多时间。</p><h2 id="建议阅读顺序" tabindex="-1">建议阅读顺序 <a class="header-anchor" href="#建议阅读顺序" aria-label="Permalink to &quot;建议阅读顺序&quot;">​</a></h2><ol><li>先看 <a href="/guide/getting-started">入门路线</a>，知道学习顺序。</li><li>再看 <a href="/concepts/base-model">底模是什么</a> 和 <a href="/concepts/components">组成部分</a>。</li><li>学会 <a href="/prompting/basics">Prompt 入门</a> 和 <a href="/lora/basics">LoRA 入门</a>。</li><li>最后看 <a href="/models/ecosystems">常见模型生态</a> 与 <a href="/resources/websites">常用网站</a>。</li></ol><h2 id="内容边界" tabindex="-1">内容边界 <a class="header-anchor" href="#内容边界" aria-label="Permalink to &quot;内容边界&quot;">​</a></h2><p>本文档按公开发布口径编写：</p><ul><li>不提供盗版模型、侵权素材或规避平台规则的方法。</li><li>不以成人内容、绕过审查或攻击性用途为教程主线。</li><li>对模型和素材的使用，优先建议查看许可证、模型卡和平台规则。</li></ul>',8)])])}const f=a(o,[["render",r]]);export{p as __pageData,f as default};
